_ALL_FIXTURES = {
    "simple_tender_go": SIMPLE_TENDER,
    "medium_tender_conditional_go": MEDIUM_TENDER,
    "trap_tender_no_go": TRAP_TENDER,
}


def get_fixture_by_name(name: str) -> Dict[str, Any]:
    """Получить фикстуру по имени."""
    if name not in _ALL_FIXTURES:
        available = ", ".join(_ALL_FIXTURES.keys())
        raise ValueError(f"Fixture '{name}' not found. Available: {available}")
    return _ALL_FIXTURES[name]


def get_all_fixtures() -> Dict[str, Dict[str, Any]]:
    """Получить все фикстуры."""
    return dict(_ALL_FIXTURES)


def get_fixtures_by_verdict(verdict: str) -> List[Dict[str, Any]]:
    """Фильтрация фикстур по ожидаемому вердикту."""
    return [
        f for f in _ALL_FIXTURES.values()
        if f.get("expected_verdict") == verdict
    ]
